refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_fruits.jpg"));
image = imresize(image, [180 240]);

red = image(:, :, 1);
green = image(:, :, 2);
[counts, redBins, greenBins] = imhist2(red, green, [64 64]);

mprintf("pixels counted: %.0f\n", sum(counts));
mprintf("image pixels  : %.0f\n", size(image, 1) * size(image, 2));

jointView = round(immat2gray(log(counts' + 1)) * 63) + 1;

subplot(1, 2, 1);
imshow(image);
title("Input image");
subplot(1, 2, 2);
imshow(jointView, hot(64));
title("Red-Green joint histogram");
